<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @foreach (var col in columns)
        {
            var colTasks = FilteredTasksForStatus(col.Status);
            <KanbanColumn ColumnName="@col.Name"
                          Status="@col.Status"
                          Tasks="colTasks"
                          CanMoveLeft="col.CanMoveLeft"
                          CanMoveRight="col.CanMoveRight"
                          OnTaskMoved="HandleTaskMoved"
                          OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly (string Name, string Status, bool CanMoveLeft, bool CanMoveRight)[] columns =
    {
        ("To Do", "To Do", false, true),
        ("In Progress", "In Progress", true, true),
        ("Done", "Done", true, false)
    };

    private static readonly Dictionary<string, string> moveLeftMap = new()
    {
        ["In Progress"] = "To Do",
        ["Done"] = "In Progress"
    };

    private static readonly Dictionary<string, string> moveRightMap = new()
    {
        ["To Do"] = "In Progress",
        ["In Progress"] = "Done"
    };

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> FilteredTasksForStatus(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task HandleTaskMoved((TaskItem Task, string Direction) move)
    {
        var statusMap = move.Direction == "left" ? moveLeftMap : moveRightMap;
        if (!statusMap.TryGetValue(move.Task.Status, out var newStatus))
            return;

        try
        {
            await TaskService.UpdateTaskStatusAsync(move.Task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == move.Task.Id);
            if (index >= 0)
            {
                allTasks[index] = move.Task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}

