@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1">
            <small class="text-muted">@Task.Assignee</small>
        </p>
        <span class="badge @PriorityClass me-2">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task)" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task)" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form to create a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="">-- Priority --</option>
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@IsSaving">
                @(IsSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-secondary btn-sm" @onclick="HandleCancel" disabled="@IsSaving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="text-danger mt-1"><small>@errorMessage</small></div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string Title { get; set; } = "";
    private string Assignee { get; set; } = "";
    private string Priority { get; set; } = "";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving { get; set; }
    private string? errorMessage;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(Title) || string.IsNullOrWhiteSpace(Assignee) || string.IsNullOrWhiteSpace(Priority))
        {
            errorMessage = "Title, assignee, and priority are required.";
            return;
        }

        errorMessage = null;
        IsSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(Title, Assignee, Priority, DueDate);
            await OnTaskCreated.InvokeAsync(created);
            ResetForm();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            IsSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        ResetForm();
        await OnCancel.InvokeAsync();
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "";
        DueDate = DateTime.Today.AddDays(7);
        errorMessage = null;
    }
}

@* A single Kanban column: header with count, task cards, and add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 60vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          IsMoving="movingTaskId == task.Id"
                          OnMoveLeft="HandleMoveLeft"
                          OnMoveRight="HandleMoveRight" />
            }

            @if (showAddForm)
            {
                <AddTaskForm DefaultStatus="@Status"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showAddForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true" disabled="@showAddForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(TaskItem Task, string Direction)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(TaskItem task)
    {
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task, "left"));
        movingTaskId = null;
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task, "right"));
        movingTaskId = null;
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

@* Summary stats bar: total tasks, per-column counts, overdue count *@

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div><strong>Total:</strong> @Tasks.Count</div>
    <div><strong>To Do:</strong> @Tasks.Count(t => t.Status == "To Do")</div>
    <div><strong>In Progress:</strong> @Tasks.Count(t => t.Status == "In Progress")</div>
    <div><strong>Done:</strong> @Tasks.Count(t => t.Status == "Done")</div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();

    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await OnSearchChanged.InvokeAsync(value);
    }
}

