    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(TaskItem task)
    {
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task, "left"));
        movingTaskId = null;
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task, "right"));
        movingTaskId = null;
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}
